// ============================================================================
// PARSE INPUT - Agente Calendario Leraysi
// ============================================================================
// Procesa y valida el input del Master AI Agent
// COMBINA: llm_output (del LLM) + state (de Input Main)
// Calcula duración y PRECIO basados en servicio + largo del cabello (determinístico)
// ============================================================================

const raw = $input.first().json;

// ============================================================================
// PASO 1: EXTRAER LLM_OUTPUT Y STATE
// ============================================================================
const data = raw.query || raw;
const llmOutput = typeof data.llm_output === 'string'
  ? JSON.parse(data.llm_output)
  : (data.llm_output || {});
const state = typeof data.state === 'string' ? JSON.parse(data.state) : (data.state || {});

// ============================================================================
// PASO 2: COMBINAR LLM_OUTPUT + STATE
// ============================================================================
const input = {
  modo: llmOutput.modo || null,
  preferencia_horario: llmOutput.preferencia_horario || null,
  accion: llmOutput.accion || null,
  nombre_clienta: llmOutput.full_name || llmOutput.nombre_clienta || state.full_name || state.nick_name,
  servicio: llmOutput.servicio || (state.servicio_interes ? [state.servicio_interes] : []),
  fecha_deseada: llmOutput.fecha_deseada || llmOutput.fecha,
  hora_deseada: llmOutput.hora_deseada || llmOutput.hora || (() => {
    const fecha = llmOutput.fecha_deseada || llmOutput.fecha;
    if (fecha && fecha.includes('T')) {
      const timePart = fecha.split('T')[1];
      if (timePart) return timePart.substring(0, 5);
    }
    return null;
  })(),
  precio: llmOutput.precio || 0,
  email: llmOutput.email || state.email || null,
  telefono: state.phone,
  clienta_id: state.lead_id,
  lead_id: state.lead_id,
  lead_row_id: state.row_id,
  conversation_id: state.conversation_id,
  image_analysis: state.image_analysis || null,
  turno_agendado: state.turno_agendado || false,
  turno_fecha: state.turno_fecha || null,
  agregar_a_turno_existente: state.agregar_a_turno_existente || llmOutput.agregar_a_turno_existente || false,
  turno_id_existente: state.odoo_turno_id || state.turno_id_existente || llmOutput.turno_id_existente || null,
  turno_precio_existente: state.turno_precio_existente || llmOutput.turno_precio_existente || 0,
  largo_cabello_raw: state.image_analysis?.length || null
};

// ============================================================================
// CONFIGURACIÓN DE SERVICIOS Y DURACIONES
// ============================================================================
const SERVICIOS_CONFIG = {
  'Corte mujer': { base_min: 60, complejidad: 'media', requiere_largo: true, precio_base: 8000 },
  'Alisado brasileño': { base_min: 180, complejidad: 'muy_compleja', requiere_largo: true, precio_base: 45000 },
  'Alisado keratina': { base_min: 240, complejidad: 'muy_compleja', requiere_largo: true, precio_base: 55000 },
  'Mechas completas': { base_min: 180, complejidad: 'muy_compleja', requiere_largo: true, precio_base: 35000 },
  'Tintura raíz': { base_min: 60, complejidad: 'compleja', requiere_largo: true, precio_base: 15000 },
  'Tintura completa': { base_min: 120, complejidad: 'muy_compleja', requiere_largo: true, precio_base: 25000 },
  'Balayage': { base_min: 240, complejidad: 'muy_compleja', requiere_largo: true, precio_base: 50000 },
  'Manicura simple': { base_min: 120, complejidad: 'media', requiere_largo: false, precio_base: 5000 },
  'Manicura semipermanente': { base_min: 180, complejidad: 'compleja', requiere_largo: false, precio_base: 8000 },
  'Pedicura': { base_min: 120, complejidad: 'media', requiere_largo: false, precio_base: 6000 },
  'Depilación cera piernas': { base_min: 120, complejidad: 'media', requiere_largo: false, precio_base: 10000 },
  'Depilación cera axilas': { base_min: 60, complejidad: 'simple', requiere_largo: false, precio_base: 4000 },
  'Depilación cera bikini': { base_min: 60, complejidad: 'simple', requiere_largo: false, precio_base: 6000 },
  'Depilación láser piernas': { base_min: 120, complejidad: 'media', requiere_largo: false, precio_base: 25000 },
  'Depilación láser axilas': { base_min: 60, complejidad: 'simple', requiere_largo: false, precio_base: 12000 }
};

const DURACION_EXTRA_LARGO = { 'corto': 0, 'medio': 60, 'largo': 120 };
const COMPLEJIDAD_POR_LARGO = { 'corto': 'media', 'medio': 'compleja', 'largo': 'muy_compleja' };
const PRECIO_MULTIPLICADOR_LARGO = { 'corto': 1.0, 'medio': 1.1, 'largo': 1.2 };

function algunServicioRequiereLargo(servicios) {
  return servicios.some(srv => {
    const config = SERVICIOS_CONFIG[srv];
    return config ? config.requiere_largo !== false : true;
  });
}

// ============================================================================
// VALIDACIÓN DE CAMPOS REQUERIDOS
// ============================================================================
const modoConsulta = input.modo === 'consultar_disponibilidad';
const camposRequeridos = modoConsulta
  ? ['servicio', 'fecha_deseada']
  : ['clienta_id', 'nombre_clienta', 'telefono', 'servicio', 'fecha_deseada'];
const camposFaltantes = camposRequeridos.filter(campo => !input[campo]);
if (camposFaltantes.length > 0) {
  throw new Error(`[ParseInput] Campos requeridos faltantes: ${camposFaltantes.join(', ')}`);
}

// ============================================================================
// EXTRACCIÓN DE DATOS
// ============================================================================
const clienta_id = input.clienta_id;
const nombre_clienta = input.nombre_clienta;
const telefono = input.telefono;
const email = input.email || null;
const servicio = Array.isArray(input.servicio) ? input.servicio : [input.servicio];
const fecha_deseada = input.fecha_deseada;
const hora_deseada = input.hora_deseada || null;
const precio = Number(input.precio) || 0;
const lead_row_id = input.lead_row_id || input.row_id;
const conversation_id = input.conversation_id || null;
const image_analysis = input.image_analysis || null;

const serviciosArray = Array.isArray(input.servicio) ? input.servicio : [input.servicio];
const requiereLargo = algunServicioRequiereLargo(serviciosArray);
const largo_cabello = requiereLargo
  ? (image_analysis?.length || input.largo_cabello_raw || null)
  : null;

// ============================================================================
// CÁLCULO DE DURACIÓN ESTIMADA
// ============================================================================
function calcularDuracion(servicios, largo) {
  let duracionTotal = 0;
  for (const srv of servicios) {
    const config = SERVICIOS_CONFIG[srv];
    if (config) {
      let duracionServicio = config.base_min;
      if (config.requiere_largo && largo) {
        duracionServicio += (DURACION_EXTRA_LARGO[largo] || 0);
      }
      duracionTotal += duracionServicio;
    } else {
      duracionTotal += 60;
    }
  }
  return Math.ceil(duracionTotal / 15) * 15;
}

function obtenerComplejidadMaxima(servicios, largo) {
  const complejidades = servicios.map(srv => {
    const config = SERVICIOS_CONFIG[srv];
    if (!config) return 'media';
    if (config.requiere_largo && largo) {
      return COMPLEJIDAD_POR_LARGO[largo] || config.complejidad;
    }
    return config.complejidad;
  });
  if (complejidades.includes('muy_compleja')) return 'muy_compleja';
  if (complejidades.includes('compleja')) return 'compleja';
  if (complejidades.includes('media')) return 'media';
  return 'simple';
}

// ============================================================================
// CÁLCULO DE PRECIO DETERMINÍSTICO
// ============================================================================
function calcularPrecio(servicios, largo) {
  let precioTotal = 0;
  for (const srv of servicios) {
    const config = SERVICIOS_CONFIG[srv];
    if (config && config.precio_base != null) {
      let precioServicio = config.precio_base;
      if (config.requiere_largo && largo) {
        precioServicio = Math.round(config.precio_base * (PRECIO_MULTIPLICADOR_LARGO[largo] || 1.0));
      }
      precioTotal += precioServicio;
    } else {
      console.log(`[ParseInput] \u26a0\ufe0f Servicio \"${srv}\" no encontrado en config, precio no calculable`);
      return null;
    }
  }
  return precioTotal;
}

const duracion_estimada = calcularDuracion(servicio, largo_cabello);
const complejidad_maxima = obtenerComplejidadMaxima(servicio, largo_cabello);
const servicio_detalle = servicio.join(' + ');

const precio_calculado = calcularPrecio(servicio, largo_cabello);
const precioFinal = precio_calculado !== null ? precio_calculado : precio;
if (precio_calculado !== null && precio > 0 && precio_calculado !== precio) {
  console.log(`[ParseInput] \ud83d\udd27 Precio corregido: LLM=$${precio}, determin\u00edstico=$${precio_calculado}`);
}

// ============================================================================
// GATE DETERMINÍSTICO
// ============================================================================
const esTurnoNuevo = !input.turno_agendado && !input.agregar_a_turno_existente;
const tieneFullName = !!(llmOutput.full_name || state.full_name);
const tieneEmail = !!email;
let gate_bloqueado = false;
const gate_datos_faltantes = [];
if (esTurnoNuevo) {
  if (!tieneFullName) gate_datos_faltantes.push('nombre completo');
  if (!tieneEmail) gate_datos_faltantes.push('email');
  gate_bloqueado = gate_datos_faltantes.length > 0;
}
if (gate_bloqueado) {
  console.log(`[ParseInput] \ud83d\udee1\ufe0f GATE BLOQUEADO: faltan ${gate_datos_faltantes.join(', ')}`);
}
const modoOutput = gate_bloqueado ? 'consultar_disponibilidad' : input.modo;

// ============================================================================
// OUTPUT
// ============================================================================
return [{
  json: {
    clienta_id, nombre_clienta, telefono, email,
    servicio, servicio_detalle, fecha_deseada, hora_deseada,
    precio: precioFinal, duracion_estimada, complejidad_maxima,
    image_analysis, largo_cabello,
    lead_id: input.lead_id, lead_row_id, conversation_id,
    turno_agendado: input.turno_agendado, turno_fecha: input.turno_fecha,
    agregar_a_turno_existente: input.agregar_a_turno_existente,
    turno_id_existente: input.turno_id_existente,
    turno_precio_existente: input.turno_precio_existente,
    modo: modoOutput, preferencia_horario: input.preferencia_horario,
    accion: input.accion,
    gate_bloqueado, gate_datos_faltantes,
    received_at: new Date().toISOString()
  }
}];

// ============================================================================
// PARSE AGENT RESPONSE - Agente Calendario Leraysi
// ============================================================================
const input = $("AnalizarDisponibilidad").first().json;
const agentOutput = $input.first().json.output;

function extractJSON(text) {
  try { return JSON.parse(text); } catch (e) {}
  let cleaned = text.replace(/```json\s*/gi, "").replace(/```\s*/g, "").trim();
  try { return JSON.parse(cleaned); } catch (e) {}
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) { try { return JSON.parse(jsonMatch[0]); } catch (e) {} }
  return { estado: "error", mensaje_para_clienta: "Error procesando la solicitud de turno" };
}

const llmResponse = extractJSON(agentOutput);

const ESTADO_A_ACCION = {
  turno_creado: "turno_creado",
  fecha_no_disponible: "sin_disponibilidad",
  turno_reprogramado: "turno_reprogramado",
  servicio_agregado: "servicio_agregado",
  error: "error",
};
const accion = ESTADO_A_ACCION[llmResponse.estado] || llmResponse.estado || "error";

let resultado = {
  clienta_id: input.clienta_id,
  nombre_clienta: input.nombre_clienta,
  telefono: input.telefono,
  email: input.email || "",
  lead_row_id: input.lead_row_id,
  conversation_id: input.conversation_id || null,
  precio: input.precio,
  servicio: input.servicio,
  servicio_detalle: input.servicio_detalle || "",
  duracion_estimada: input.duracion_estimada || 60,
  complejidad_maxima: input.complejidad_maxima || "media",
  accion: accion,
  mensaje_para_clienta: llmResponse.mensaje_para_clienta,
  alternativas: llmResponse.alternativas || [],
};

// CASO: TURNO CREADO
if (llmResponse.estado === "turno_creado") {
  const mpPreferenceId = llmResponse.mp_preference_id || llmResponse.link_pago?.match(/preference-id=([^&\s]+)/)?.[1] || "";
  const [fechaTurno, horaTurno] = (llmResponse.fecha_hora || "").split(" ");
  resultado = {
    ...resultado,
    fecha_turno: fechaTurno || input.fecha_solicitada,
    hora_sugerida: horaTurno || input.hora_deseada || "09:00",
    odoo_turno_id: llmResponse.turno_id,
    mp_preference_id: mpPreferenceId,
    link_pago: llmResponse.link_pago || "",
    estado_turno: "pendiente_pago",
    sena_monto: llmResponse.sena || Math.round((input.precio || 0) * 0.3),
  };
}

// CASO: FECHA NO DISPONIBLE
if (llmResponse.estado === "fecha_no_disponible") {
  resultado = {
    ...resultado,
    fecha_solicitada: llmResponse.fecha_solicitada || input.fecha_solicitada,
    motivo_no_disponible: llmResponse.motivo,
  };
}

// CASO: TURNO REPROGRAMADO
if (llmResponse.estado === "turno_reprogramado") {
  const [fechaNueva, horaNueva] = (llmResponse.fecha_hora_nueva || "").split(" ");
  const mpPreferenceId = llmResponse.mp_preference_id || llmResponse.link_pago?.match(/preference-id=([^&\s]+)/)?.[1] || "";
  resultado = {
    ...resultado,
    odoo_turno_id: llmResponse.odoo_turno_id,
    turno_id_anterior: llmResponse.turno_id_anterior,
    turno_id_nuevo: llmResponse.turno_id_nuevo,
    fecha_turno: fechaNueva,
    hora_sugerida: horaNueva || "09:00",
    fecha_hora_anterior: llmResponse.fecha_hora_anterior,
    fecha_hora_nueva: llmResponse.fecha_hora_nueva,
    mp_preference_id: mpPreferenceId,
    link_pago: llmResponse.link_pago || null,
    calendario_actualizado: true,
    motivo_reprogramacion: llmResponse.motivo || "Solicitud de la clienta",
  };
}

// CASO: SERVICIO AGREGADO
if (llmResponse.estado === "servicio_agregado") {
  const [fechaTurno, horaTurno] = (llmResponse.fecha_hora || "").split(" ");
  const mpPreferenceId = llmResponse.mp_preference_id || llmResponse.link_pago?.match(/preference-id=([^&\s]+)/)?.[1] || "";
  let servicioDetalleCombinado = "";
  let serviciosArray = [];
  if (llmResponse.servicios_combinados) {
    servicioDetalleCombinado = llmResponse.servicios_combinados;
    serviciosArray = servicioDetalleCombinado.split(" + ").map(s => s.trim()).filter(Boolean);
  } else {
    const servicioExistente = input.turno_servicio_existente || "";
    const serviciosInputArray = Array.isArray(input.servicio) ? input.servicio : [input.servicio];
    const servicioExistenteNorm = servicioExistente.toLowerCase().trim();
    const servicioNuevoRaw = serviciosInputArray.find(s => s && s.toLowerCase().trim() !== servicioExistenteNorm) || serviciosInputArray[serviciosInputArray.length - 1] || "";
    const servicioNuevo = servicioNuevoRaw ? servicioNuevoRaw.charAt(0).toUpperCase() + servicioNuevoRaw.slice(1).replace(/_/g, " ") : "";
    serviciosArray = [];
    if (servicioExistente) serviciosArray.push(servicioExistente);
    if (servicioNuevo && servicioNuevo.toLowerCase() !== servicioExistente.toLowerCase()) serviciosArray.push(servicioNuevo);
    servicioDetalleCombinado = serviciosArray.join(" + ");
  }
  const fechaTurnoFinal = fechaTurno || (input.turno_fecha?.includes("T") ? input.turno_fecha.split("T")[0] : input.turno_fecha?.split(" ")[0]) || "";
  const horaTurnoFinal = horaTurno || (input.turno_fecha?.includes("T") ? input.turno_fecha.split("T")[1]?.slice(0, 5) : input.turno_fecha?.split(" ")[1]) || "09:00";
  // Safety net: precio determin\u00edstico (ParseInput) sobre precio del LLM
  const precioExDet = Number(input.turno_precio_existente) || 0;
  const precioNuevoDet = Number(input.precio) || 0;
  const precioTotalDet = precioExDet + precioNuevoDet;
  const precioTotalFinal = precioTotalDet > 0 ? precioTotalDet : (llmResponse.precio_total || 0);
  if (llmResponse.precio_total && precioTotalDet > 0 && llmResponse.precio_total !== precioTotalDet) {
    console.log(`[ParseAgentResponse] \ud83d\udd27 Precio servicio_agregado corregido: LLM=$${llmResponse.precio_total}, det=$${precioTotalDet}`);
  }
  resultado = {
    ...resultado,
    odoo_turno_id: llmResponse.turno_id,
    fecha_turno: fechaTurnoFinal,
    hora_sugerida: horaTurnoFinal,
    servicio: serviciosArray,
    servicio_detalle: servicioDetalleCombinado,
    precio: precioTotalFinal,
    duracion_estimada: llmResponse.duracion_estimada || input.duracion_estimada || 60,
    complejidad_maxima: llmResponse.complejidad_maxima || input.complejidad_maxima || "media",
    sena_monto: llmResponse.sena || Math.round((precioTotalFinal || 0) * 0.3),
    mp_preference_id: mpPreferenceId,
    link_pago: llmResponse.link_pago || "",
    estado_turno: "pendiente_pago",
  };
}

return [{ json: resultado }];

// ============================================================================
// BUILD AGENT PROMPT - Construye el User Message para Agente Calendario
// ============================================================================
const data = $input.first().json;

const fechaSolicitadaRaw = data.fecha_solicitada || "";
const fechaSoloParte = fechaSolicitadaRaw.includes("T")
  ? fechaSolicitadaRaw.split("T")[0]
  : fechaSolicitadaRaw.split(" ")[0];
const horaSolicitadaParte = fechaSolicitadaRaw.includes("T")
  ? fechaSolicitadaRaw.split("T")[1]?.slice(0, 5)
  : fechaSolicitadaRaw.split(" ")[1]?.slice(0, 5);

const horaDeseada = horaSolicitadaParte || data.hora_deseada || "09:00";
const senaCalculada = Math.round((data.precio || 0) * 0.3);
const fechaHoraCompleta = `${fechaSoloParte} ${horaDeseada}`;

const formatearFechaHumana = (fechaStr) => {
  if (!fechaStr) return "fecha no especificada";
  const soloFecha = fechaStr.includes("T")
    ? fechaStr.split("T")[0]
    : fechaStr.split(" ")[0];
  const fecha = new Date(soloFecha + "T12:00:00");
  if (isNaN(fecha.getTime())) return "fecha invalida";
  const dias = [
    "domingo",
    "lunes",
    "martes",
    "miercoles",
    "jueves",
    "viernes",
    "sabado",
  ];
  const meses = [
    "enero",
    "febrero",
    "marzo",
    "abril",
    "mayo",
    "junio",
    "julio",
    "agosto",
    "septiembre",
    "octubre",
    "noviembre",
    "diciembre",
  ];
  return `${dias[fecha.getDay()]} ${fecha.getDate()} de ${meses[fecha.getMonth()]}`;
};

const fechaHumana = formatearFechaHumana(data.fecha_solicitada);
const servicioDisplay = data.servicio_detalle || data.servicio || "servicio";

const turnoExistente = data.turno_agendado === true;
const serviciosSolicitados = Array.isArray(data.servicio)
  ? data.servicio.map((s) => s.toLowerCase().trim())
  : [(data.servicio || "").toLowerCase().trim()];

let servicioTurnoExistente = null;
if (data.turno_servicio_existente) {
  servicioTurnoExistente =
    typeof data.turno_servicio_existente === "object"
      ? (data.turno_servicio_existente.value || "").toLowerCase().trim()
      : data.turno_servicio_existente.toLowerCase().trim();
}

let esReprogramacion = false;
let esAgregarServicio = false;
let esTurnoAdicional = false;

const turnoFechaExistente = data.turno_fecha
  ? data.turno_fecha.includes("T")
    ? data.turno_fecha.split("T")[0]
    : data.turno_fecha.split(" ")[0]
  : null;
const turnoIdExistente = data.turno_id_existente || data.odoo_turno_id || null;

// Detección explícita: el Master Agent envía accion: "reprogramar"
if (data.accion === "reprogramar") {
  esReprogramacion = true;
} else if (turnoExistente) {
  if (servicioTurnoExistente) {
    const servicioExistenteNorm = servicioTurnoExistente.toLowerCase().trim();
    const tieneServicioNuevo = serviciosSolicitados.some(
      (s) =>
        !s.includes(servicioExistenteNorm) &&
        !servicioExistenteNorm.includes(s),
    );
    const serviciosCoinciden = !tieneServicioNuevo;
    const fechasCoinciden =
      turnoFechaExistente &&
      fechaSoloParte &&
      turnoFechaExistente === fechaSoloParte;
    if (serviciosCoinciden) esReprogramacion = true;
    else if (!serviciosCoinciden && fechasCoinciden && turnoIdExistente)
      esAgregarServicio = true;
    else esTurnoAdicional = true;
  } else {
    esTurnoAdicional = true;
  }
}

let instruccionTarea = "";
let jsonRespuestaEsperada = "";

if (esReprogramacion && data.fecha_disponible) {
  const mensajeClientaReprogramado = `Listo ${data.nombre_clienta || "reina"}! Tu turno fue reprogramado para el ${fechaHumana} a las ${horaDeseada}. Te enviamos un email de confirmacion.`;
  instruccionTarea = `## REPROGRAMAR TURNO\n\n### PASO 1: Llamar a la tool \`leraysi_reprogramar_turno\`\n\nUsar EXACTAMENTE estos parametros:\n\n\`\`\`json\n{\n  "lead_id": ${data.lead_id || "null"},\n  "nueva_fecha_hora": "${fechaHoraCompleta}",\n  "motivo": "Solicitud de la clienta"\n}\n\`\`\`\n\n### PASO 2: Despues de llamar la tool, responder con este JSON\n\nReemplazar los valores {ENTRE_LLAVES} con los datos de la respuesta de la tool:\n\n\`\`\`json\n{\n  "estado": "turno_reprogramado",\n  "odoo_turno_id": {turno_id_nuevo de la respuesta si existe, sino turno_id_anterior},\n  "turno_id_anterior": {turno_id_anterior de la respuesta},\n  "turno_id_nuevo": {turno_id_nuevo de la respuesta o null},\n  "lead_id": ${data.lead_id || "null"},\n  "fecha_hora_anterior": "{fecha_hora_anterior de la respuesta}",\n  "fecha_hora_nueva": "${fechaHoraCompleta}",\n  "servicio": "${data.servicio || "otro"}",\n  "link_pago": "{link_pago de la respuesta si existe, o null}",\n  "mp_preference_id": "{mp_preference_id de la respuesta si existe, o null}",\n  "mensaje_para_clienta": "${mensajeClientaReprogramado}"\n}\n\`\`\``;
} else if (esAgregarServicio && data.fecha_disponible) {
  const precioExistente = data.turno_precio_existente || 0;
  const precioNuevo = data.precio || 0;
  const precioTotal = precioExistente + precioNuevo;
  const senaTotalCalculada = Math.round(precioTotal * 0.3);
  const senaPagadaExistente = data.turno_sena_pagada || Math.round(precioExistente * 0.3);
  const senaDiferencial = senaTotalCalculada - senaPagadaExistente;
  // Duración combinada: existente + nuevo servicio
  const duracionExistente = data.turno_duracion_existente || 0;
  const duracionNueva = data.duracion_estimada || 60;
  const duracionCombinada = duracionExistente + duracionNueva;
  // Complejidad: MAX entre existente y nuevo
  const COMPLEJIDAD_ORDER = { simple: 1, media: 2, compleja: 3, muy_compleja: 4 };
  const complejidadExistente = data.turno_complejidad_existente || "media";
  const complejidadNueva = data.complejidad_maxima || "media";
  const complejidadCombinada = (COMPLEJIDAD_ORDER[complejidadExistente] || 2) >= (COMPLEJIDAD_ORDER[complejidadNueva] || 2)
    ? complejidadExistente : complejidadNueva;
  const servicioExistenteDisplay =
    data.turno_servicio_existente || "servicio existente";
  const serviciosArray = Array.isArray(data.servicio)
    ? data.servicio
    : [data.servicio];
  const servicioExistenteNorm = (data.turno_servicio_existente || "")
    .toLowerCase()
    .trim();
  const servicioNuevo =
    serviciosArray.find(
      (s) => s && s.toLowerCase().trim() !== servicioExistenteNorm,
    ) ||
    serviciosArray[serviciosArray.length - 1] ||
    "otro";
  const serviciosCombinados = `${servicioExistenteDisplay} + ${servicioNuevo}`;
  const mensajeClientaAgregado = `Listo ${data.nombre_clienta || "reina"}! Actualice tu turno del ${fechaHumana}. Ahora tenes: ${serviciosCombinados}. Total: $${precioTotal.toLocaleString("es-AR")}. Sena adicional a pagar: $${senaDiferencial.toLocaleString("es-AR")}. {LINK_PAGO_MSG}`;
  instruccionTarea = `## AGREGAR SERVICIO AL TURNO EXISTENTE\n\n### PASO 1: Llamar a la tool \`leraysi_agregar_servicio_turno\`\n\nUsar EXACTAMENTE estos parametros:\n\n\`\`\`json\n{\n  "turno_id": ${turnoIdExistente},\n  "nuevo_servicio": "${servicioNuevo}",\n  "nuevo_servicio_detalle": "${servicioNuevo}",\n  "nuevo_precio": ${precioNuevo},\n  "duracion_estimada": ${duracionCombinada},\n  "complejidad_maxima": "${complejidadCombinada}"\n}\n\`\`\`\n\n### PASO 2: Despues de llamar la tool, responder con este JSON\n\n\`\`\`json\n{\n  "estado": "servicio_agregado",\n  "turno_id": ${turnoIdExistente},\n  "lead_id": ${data.lead_id || "null"},\n  "fecha_hora": "${fechaHoraCompleta}",\n  "servicios_combinados": "{servicio_detalle de la respuesta}",\n  "precio_total": {precio_total de la respuesta},\n  "duracion_estimada": ${duracionCombinada},\n  "complejidad_maxima": "${complejidadCombinada}",\n  "sena": {sena de la respuesta},\n  "link_pago": "{link_pago de la respuesta}",\n  "mp_preference_id": "{mp_preference_id de la respuesta}",\n  "mensaje_para_clienta": "${mensajeClientaAgregado}"\n}\n\`\`\``;
} else if (data.fecha_disponible) {
  const mensajeClientaTemplate = `Listo ${data.nombre_clienta || "reina"}! Tu turno de ${servicioDisplay.toLowerCase()} esta reservado para el ${fechaHumana} a las ${horaDeseada}. Para confirmarlo, paga la sena de $${senaCalculada.toLocaleString("es-AR")} en este link: {LINK_PAGO}`;
  instruccionTarea = `## FECHA DISPONIBLE - CREAR TURNO\n\n### PASO 1: Llamar a la tool \`leraysi_crear_turno\`\n\nUsar EXACTAMENTE estos parametros:\n\n\`\`\`json\n{\n  "clienta": "${data.nombre_clienta || ""}",\n  "telefono": "${data.telefono || ""}",\n  "servicio": "${data.servicio || "otro"}",\n  "fecha_hora": "${fechaHoraCompleta}",\n  "precio": ${data.precio || 0},\n  "duracion_estimada": ${data.duracion_estimada || 60},\n  "complejidad_maxima": "${data.complejidad_maxima || "media"}",\n  "lead_id": ${data.lead_id || "null"}${data.email ? `,\n  "email": "${data.email}"` : ""}${data.servicio_detalle ? `,\n  "servicio_detalle": "${data.servicio_detalle}"` : ""}\n}\n\`\`\`\n\n### PASO 2: Despues de llamar la tool, responder con este JSON\n\n\`\`\`json\n{\n  "estado": "turno_creado",\n  "turno_id": {turnoId de la respuesta},\n  "lead_id": ${data.lead_id || "null"},\n  "fecha_hora": "${fechaHoraCompleta}",\n  "servicio": "${data.servicio || "otro"}",\n  "servicio_detalle": "${servicioDisplay}",\n  "precio": ${data.precio || 0},\n  "duracion_estimada": ${data.duracion_estimada || 60},\n  "complejidad_maxima": "${data.complejidad_maxima || "media"}",\n  "sena": {sena de la respuesta},\n  "link_pago": "{link_pago de la respuesta}",\n  "mp_preference_id": "{mp_preference_id de la respuesta}",\n  "mensaje_para_clienta": "${mensajeClientaTemplate}"\n}\n\`\`\`\n\n**IMPORTANTE:** En mensaje_para_clienta, reemplazar {LINK_PAGO} con el link_pago real de la respuesta.`;
} else {
  const alternativasTexto =
    data.alternativas?.length > 0
      ? data.alternativas.map((a) => `${a.nombre_dia} ${a.fecha}`).join(", ")
      : "No hay disponibilidad esta semana";
  const alternativasArray =
    data.alternativas?.map((a) => `"${a.nombre_dia} ${a.fecha}"`) || [];
  const mensajeClientaNoDisponible = `Disculpa, el ${fechaHumana} no tenemos disponibilidad (${(data.motivo_no_disponible || "agenda completa").toLowerCase()}). Te puedo ofrecer: ${alternativasTexto}. Cual te queda mejor?`;
  instruccionTarea = `## FECHA NO DISPONIBLE\n\n**NO llamar ninguna tool.**\n\nResponder UNICAMENTE con este JSON:\n\n\`\`\`json\n{\n  "estado": "fecha_no_disponible",\n  "fecha_solicitada": "${data.fecha_solicitada}",\n  "motivo": "${data.motivo_no_disponible || "Sin disponibilidad"}",\n  "alternativas": [${alternativasArray.join(", ")}],\n  "mensaje_para_clienta": "${mensajeClientaNoDisponible}"\n}\n\`\`\``;
}

const userMessage = `# SOLICITUD DE TURNO - Estilos Leraysi\n\n## Datos de la Solicitud\n\n| Campo | Valor |\n|-------|-------|\n| **Clienta** | ${data.nombre_clienta || "No proporcionado"} |\n| **Telefono** | ${data.telefono || "No proporcionado"} |\n| **Email** | ${data.email || "No proporcionado"} |\n| **Lead ID** | ${data.lead_id || "N/A"} |\n| **Servicio** | ${servicioDisplay} |\n| **Complejidad** | ${data.complejidad_maxima || "media"} |\n| **Duracion** | ${data.duracion_estimada || 60} min |\n| **Precio** | $${(data.precio || 0).toLocaleString("es-AR")} |\n| **Sena (30%)** | $${senaCalculada.toLocaleString("es-AR")} |\n| **Fecha solicitada** | ${data.fecha_solicitada} (${fechaHumana}) |\n| **Hora** | ${horaDeseada} |\n| **Disponibilidad** | ${data.fecha_disponible ? "DISPONIBLE" : "NO DISPONIBLE"} |\n\n## Disponibilidad de la Semana\n\n${data.resumen_disponibilidad || "No disponible"}\n\n---\n\n${instruccionTarea}`;

return [
  {
    json: {
      ...data,
      userMessage,
      _precalculado: {
        hora: horaDeseada,
        duracion_estimada: esAgregarServicio
          ? (data.turno_duracion_existente || 0) + (data.duracion_estimada || 60)
          : (data.duracion_estimada || 60),
        complejidad_maxima: esAgregarServicio
          ? (() => {
              const ORD = { simple: 1, media: 2, compleja: 3, muy_compleja: 4 };
              const ex = data.turno_complejidad_existente || "media";
              const nw = data.complejidad_maxima || "media";
              return (ORD[ex] || 2) >= (ORD[nw] || 2) ? ex : nw;
            })()
          : (data.complejidad_maxima || "media"),
        sena: esAgregarServicio
          ? Math.round((data.precio || 0) * 0.3)
          : senaCalculada,
        fecha_hora_completa: fechaHoraCompleta,
        fecha_humana: fechaHumana,
        servicio_display: servicioDisplay,
      },
    },
  },
];

// ============================================================================
// PREPARAR TURNO BASEROW - Agente Calendario Leraysi
// ============================================================================
// Transforma datos de ParseAgentResponse al formato de TurnosLeraysi
// Campos según TABLA-TURNOS-LERAYSI.md
// ============================================================================
// NODO: PrepararTurnoBaserow (Code)
// INPUT: ParseAgentResponse via IF_Agendar (True Branch)
// OUTPUT: Campos listos para Baserow Create Row
// ============================================================================

const data = $input.first().json;

// ============================================================================
// CONFIGURACIÓN
// ============================================================================
const CONFIG = {
  expiracion_minutos: 120, // 2 horas para pagar la seña
};

// Calcular timestamps
const ahora = new Date();
const expiraAt = new Date(
  ahora.getTime() + CONFIG.expiracion_minutos * 60 * 1000,
);

// Formatear fecha para Baserow API: ISO 8601 con timezone Argentina
function formatBaserowDatetime(date) {
  // Ajustar UTC a Argentina (UTC-3)
  const argentinaTime = new Date(date.getTime() - 3 * 60 * 60 * 1000);
  const offset = "-03:00";
  const year = argentinaTime.getUTCFullYear();
  const month = String(argentinaTime.getUTCMonth() + 1).padStart(2, "0");
  const day = String(argentinaTime.getUTCDate()).padStart(2, "0");
  const hours = String(argentinaTime.getUTCHours()).padStart(2, "0");
  const minutes = String(argentinaTime.getUTCMinutes()).padStart(2, "0");
  const seconds = String(argentinaTime.getUTCSeconds()).padStart(2, "0");
  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}${offset}`;
}

// ============================================================================
// CONSTRUIR REGISTRO PARA BASEROW (TurnosLeraysi)
// ============================================================================
const turnoBaserow = {
  // === Fecha y Hora ===
  fecha: data.fecha_turno,
  hora: data.hora_sugerida || "09:00",

  // === Relación con Lead ===
  clienta_id: data.lead_row_id ? [data.lead_row_id] : [],

  // === Datos de la Clienta (desnormalizados) ===
  nombre_clienta: data.nombre_clienta,
  telefono: data.telefono,
  email: data.email || "",

  // === Servicio ===
  servicio: Array.isArray(data.servicio) ? data.servicio : [data.servicio],
  servicio_detalle: data.servicio_detalle || "",
  complejidad_maxima: data.complejidad_maxima || "media",
  // duracion_min se agrega condicionalmente abajo

  // === Precio y Seña ===
  // precio y sena_monto se agregan condicionalmente abajo
  sena_pagada: false,

  // === Estado ===
  estado: data.estado_turno || "pendiente_pago",

  // === Mercado Pago ===
  mp_preference_id: data.mp_preference_id || "",
  mp_link: data.link_pago || "",
  mp_payment_id: "", // Se llena cuando se confirma el pago

  // === Timestamps ===
  created_at: formatBaserowDatetime(ahora),
  expira_at: formatBaserowDatetime(expiraAt),
  // confirmado_at se agrega solo cuando tiene valor (ver abajo)

  // === Notas ===
  notas: `Turno creado via chatbot. Servicio: ${data.servicio}`,
};

// Agregar campos numéricos solo si tienen valor (Baserow no acepta null)
turnoBaserow.duracion_min = data.duracion_estimada || 60;
if (data.precio != null) {
  turnoBaserow.precio = data.precio;
}
if (data.sena_monto != null) {
  turnoBaserow.sena_monto = data.sena_monto;
}
if (data.odoo_turno_id) {
  turnoBaserow.odoo_turno_id = data.odoo_turno_id;
}
if (data.conversation_id) {
  turnoBaserow.conversation_id = data.conversation_id;
}

// ============================================================================
// OUTPUT
// ============================================================================
return [
  {
    json: {
      // Campos para Baserow (directo)
      ...turnoBaserow,

      // Preservar datos para FormatearRespuestaExito
      _meta: {
        accion: data.accion,
        mensaje_para_clienta: data.mensaje_para_clienta,
        lead_row_id: data.lead_row_id,
      },
    },
  },
];

// ============================================================================
// FORMATEAR RESPUESTA EXITO - Agente Calendario Leraysi
// ============================================================================
// Construye la respuesta final exitosa para devolver al Master Agent
// ============================================================================
// NODO: FormatearRespuestaExito (Code)
// INPUT: CrearTurnoBaserow (respuesta de Baserow con ID del row creado)
// OUTPUT: Respuesta estructurada para Return
// ============================================================================

const baserowResponse = $input.first().json;

// Recuperar metadata del nodo anterior (PrepararTurnoBaserow)
const metaData = $('PrepararTurnoBaserow').first().json._meta;

// El ID del turno creado en Baserow
const turnoRowId = baserowResponse.id;

// ============================================================================
// OUTPUT PARA MASTER AGENT
// ============================================================================
return [{
  json: {
    success: true,
    accion: metaData.accion,
    turno_id: turnoRowId,
    mensaje_para_clienta: metaData.mensaje_para_clienta,
    lead_row_id: metaData.lead_row_id
  }
}];

// ============================================================================
// ANALIZAR DISPONIBILIDAD - Agente Calendario Leraysi
// ============================================================================
// INPUT: ParseInput (datos del turno) + GetTurnosSemana (turnos existentes)
// OUTPUT: Disponibilidad calculada + alternativas pre-calculadas si no hay cupo
// ============================================================================

// Obtener turnos (puede ser array vacío)
const turnosRaw = $('GetTurnosSemana').all();
const turnos = turnosRaw.length > 0 ? turnosRaw.map(item => item.json) : [];

const input = $('ParseInput').first().json;

// Configuración de capacidad máxima por día según complejidad
// Horario: 9am-7pm (10 horas disponibles)
const CAPACIDAD = {
  max_muy_compleja: 2,  // Servicios muy complejos (Alisados, Balayage, Mechas, Tintura completa)
  max_compleja: 3,      // Servicios complejos (Tintura raíz, Manicura semipermanente)
  max_media: 4,         // Servicios medios (Corte, Manicura simple, Pedicura, Depilación cera/láser piernas)
  max_simple: 5,        // Servicios simples (Depilación axilas, bikini)
  max_turnos_dia: 8     // Máximo absoluto de turnos por día
};

// Agrupar turnos por fecha
const turnosPorDia = {};

turnos.forEach(turno => {
  const fecha = turno.fecha?.split('T')[0];
  if (!fecha) return;

  if (!turnosPorDia[fecha]) {
    turnosPorDia[fecha] = {
      fecha,
      turnos: [],
      count_total: 0,
      count_simple: 0,
      count_media: 0,
      count_compleja: 0,
      count_muy_compleja: 0,
      duracion_total: 0
    };
  }

  turnosPorDia[fecha].turnos.push(turno);
  turnosPorDia[fecha].count_total++;
  turnosPorDia[fecha].duracion_total += Number(turno.duracion_min) || 0;

  // Usar complejidad_maxima del turno (campo unificado con ParseInput)
  const complejidad = turno.complejidad_maxima?.value || turno.complejidad_maxima || 'media';
  if (complejidad === 'simple') turnosPorDia[fecha].count_simple++;
  else if (complejidad === 'media') turnosPorDia[fecha].count_media++;
  else if (complejidad === 'compleja') turnosPorDia[fecha].count_compleja++;
  else if (complejidad === 'muy_compleja') turnosPorDia[fecha].count_muy_compleja++;
});

// Generar próximos 30 días con disponibilidad (cobertura de 1 mes)
const dias = [];
const hoy = new Date();

for (let i = 0; i < 30; i++) {
  const fecha = new Date(hoy);
  fecha.setDate(hoy.getDate() + i);
  const fechaStr = fecha.toISOString().split('T')[0];

  const diaSemana = fecha.getDay();
  const nombreDia = ['Domingo', 'Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'][diaSemana];

  // Domingo cerrado
  if (diaSemana === 0) {
    dias.push({
      fecha: fechaStr,
      nombre_dia: nombreDia,
      abierto: false,
      disponible: false,
      motivo: 'Cerrado'
    });
    continue;
  }

  const datosDia = turnosPorDia[fechaStr] || {
    count_total: 0,
    count_simple: 0,
    count_media: 0,
    count_compleja: 0,
    count_muy_compleja: 0,
    duracion_total: 0
  };

  // Verificar capacidad por nivel de complejidad
  const puedeRecibirMuyCompleja = datosDia.count_muy_compleja < CAPACIDAD.max_muy_compleja;
  const puedeRecibirCompleja = datosDia.count_compleja < CAPACIDAD.max_compleja;
  const puedeRecibirMedia = datosDia.count_media < CAPACIDAD.max_media;
  const puedeRecibirSimple = datosDia.count_simple < CAPACIDAD.max_simple;
  const puedeRecibirMas = datosDia.count_total < CAPACIDAD.max_turnos_dia;

  // 600 minutos = 10 horas (9am-7pm)
  const cargaPorcentaje = Math.round((datosDia.duracion_total / 600) * 100);

  dias.push({
    fecha: fechaStr,
    nombre_dia: nombreDia,
    abierto: true,
    turnos_agendados: datosDia.count_total,
    // Conteo por complejidad
    muy_complejos_agendados: datosDia.count_muy_compleja,
    complejos_agendados: datosDia.count_compleja,
    medios_agendados: datosDia.count_media,
    simples_agendados: datosDia.count_simple,
    duracion_total_min: datosDia.duracion_total,
    carga_porcentaje: cargaPorcentaje,
    // Capacidad disponible por complejidad
    puede_recibir_muy_compleja: puedeRecibirMuyCompleja,
    puede_recibir_compleja: puedeRecibirCompleja,
    puede_recibir_media: puedeRecibirMedia,
    puede_recibir_simple: puedeRecibirSimple,
    puede_recibir_turno: puedeRecibirMas,
    disponible: puedeRecibirMas
  });
}

// ============================================================================
// VERIFICAR DISPONIBILIDAD DEL DÍA SOLICITADO Y GENERAR ALTERNATIVAS
// ============================================================================
// Extraer solo la fecha (sin hora) para comparación - soporta ISO con T o solo fecha
const fechaSolicitadaRaw = input.fecha_deseada || '';
const fechaSolicitada = fechaSolicitadaRaw.includes('T')
  ? fechaSolicitadaRaw.split('T')[0]
  : fechaSolicitadaRaw.split(' ')[0];
const diaSolicitado = dias.find(d => d.fecha === fechaSolicitada);

// Determinar si la fecha está disponible
const fechaDisponible = diaSolicitado?.abierto && diaSolicitado?.disponible;

// Pre-calcular alternativas si el día NO está disponible
let alternativas = [];
let motivoNoDisponible = null;

if (!fechaDisponible) {
  // Determinar el motivo
  if (!diaSolicitado) {
    motivoNoDisponible = 'Fecha fuera de rango (solo se pueden agendar turnos en los próximos 30 días)';
  } else if (!diaSolicitado.abierto) {
    motivoNoDisponible = 'Cerrado (Domingo)';
  } else if (!diaSolicitado.disponible) {
    motivoNoDisponible = `Agenda llena (${diaSolicitado.turnos_agendados} turnos, ${diaSolicitado.carga_porcentaje}% de capacidad)`;
  }

  // Buscar los próximos 3 días disponibles como alternativas
  alternativas = dias
    .filter(d => d.abierto && d.disponible)
    .slice(0, 3)
    .map(d => ({
      fecha: d.fecha,
      nombre_dia: d.nombre_dia,
      turnos_agendados: d.turnos_agendados,
      carga_porcentaje: d.carga_porcentaje
    }));
}

// Resumen para el agente
const resumen = dias
  .filter(d => d.abierto)
  .map(d => {
    let estado = '';
    if (!d.disponible) estado = '❌ Lleno';
    else if (d.carga_porcentaje >= 70) estado = '⚠️ Casi lleno';
    else if (d.carga_porcentaje >= 40) estado = '📅 Moderado';
    else estado = '✅ Disponible';

    return `${d.nombre_dia} ${d.fecha}: ${estado} (${d.turnos_agendados} turnos, ${d.carga_porcentaje}% carga)`;
  })
  .join('\n');

// ============================================================================
// EXTRAER SERVICIO DEL TURNO EXISTENTE (para detectar reprogramación vs turno adicional)
// ============================================================================
// Si la usuaria tiene turno_agendado=true, buscamos su turno en los turnos de la semana
// para extraer el servicio y poder compararlo con el servicio solicitado
//
// IMPORTANTE: En Baserow tabla TurnosLeraysi, el linked field es "clienta_id"
// que apunta a la tabla LeadsLeraysi. El formato es:
// - Array de objetos: [{id: 116, value: "428"}] donde id es el ROW_ID del lead
//
// Debemos comparar contra lead_row_id (el row_id de Baserow), NO contra lead_id (Odoo ID)
let turnoServicioExistente = null;
let turnoIdExistente = null;
let turnoPrecioExistente = null;
let turnoDuracionExistente = null;
let turnoComplejidadExistente = null;
let turnoSenaPagada = null;

if (input.turno_agendado && input.lead_row_id) {
  // Buscar turno de esta usuaria por lead_row_id (ID de fila en Baserow)
  const turnoUsuaria = turnos.find(t => {
    // El campo en Baserow se llama "clienta_id" (linked field a LeadsLeraysi)
    let turnoClientaRowId = null;
    if (Array.isArray(t.clienta_id) && t.clienta_id.length > 0) {
      // Formato: [{id: 116, value: "428"}] - id es el row_id del lead
      turnoClientaRowId = t.clienta_id[0]?.id;
    } else if (t.clienta_id && typeof t.clienta_id === 'object') {
      // Formato objeto directo
      turnoClientaRowId = t.clienta_id.id || t.clienta_id.value;
    } else {
      // Formato: valor directo
      turnoClientaRowId = t.clienta_id;
    }

    return turnoClientaRowId && String(turnoClientaRowId) === String(input.lead_row_id);
  });

  if (turnoUsuaria) {
    // Extraer el servicio existente completo
    // PRIORIDAD: servicio_detalle (string concatenado "Manicura simple + Pedicura")
    // porque el multi-select 'servicio' solo da valores individuales y antes
    // solo tomábamos el primero, perdiendo servicios intermedios con 3+ servicios
    let servicioValue = null;
    if (turnoUsuaria.servicio_detalle) {
      // Mejor fuente: string concatenado con todos los servicios
      servicioValue = turnoUsuaria.servicio_detalle;
    } else if (Array.isArray(turnoUsuaria.servicio) && turnoUsuaria.servicio.length > 0) {
      // Fallback: unir todos los valores del multi-select
      servicioValue = turnoUsuaria.servicio.map(s => s?.value || s).join(' + ');
    } else if (turnoUsuaria.servicio?.value) {
      servicioValue = turnoUsuaria.servicio.value;
    } else {
      servicioValue = turnoUsuaria.servicio;
    }
    turnoServicioExistente = servicioValue || null;

    // Extraer odoo_turno_id (ID del turno en Odoo)
    turnoIdExistente = turnoUsuaria.odoo_turno_id || null;

    // Extraer precio del turno existente (para calcular seña diferencial)
    turnoPrecioExistente = turnoUsuaria.precio ? Number(turnoUsuaria.precio) : null;

    // Extraer duración del turno existente (para sumar al agregar servicio)
    turnoDuracionExistente = turnoUsuaria.duracion_min ? Number(turnoUsuaria.duracion_min) : null;

    // Extraer complejidad del turno existente (para MAX al agregar servicio)
    turnoComplejidadExistente = turnoUsuaria.complejidad_maxima?.value || turnoUsuaria.complejidad_maxima || null;

    // Extraer seña pagada del turno existente (para calcular diferencial)
    turnoSenaPagada = turnoUsuaria.sena_monto ? Number(turnoUsuaria.sena_monto) : null;
  }
}

// ============================================================================
// CÁLCULO DE SLOTS POR HORA (solo para modo consultar_disponibilidad)
// ============================================================================
const modo = input.modo || null;
let slotsRecomendados = [];
let esJornadaCompleta = false;

if (modo === 'consultar_disponibilidad') {
  const APERTURA = 9 * 60;   // 09:00 = 540 min
  const CIERRE = 19 * 60;    // 19:00 = 1140 min
  const STEP = 30;            // granularidad 30 min
  const duracionServicio = input.duracion_estimada || 60;
  const horaPreferida = input.hora_deseada ? (() => {
    const parts = input.hora_deseada.split(':');
    return parseInt(parts[0]) * 60 + parseInt(parts[1] || '0');
  })() : null;
  const preferencia = input.preferencia_horario || null;

  const ahora = new Date();
  // Usar hora Argentina (UTC-3)
  const ahoraArgentina = new Date(ahora.getTime() - 3 * 60 * 60 * 1000);
  const ahoraMin = ahoraArgentina.getUTCHours() * 60 + ahoraArgentina.getUTCMinutes();
  const hoyStr = ahoraArgentina.toISOString().split('T')[0];

  function horaToMinutos(horaStr) {
    if (!horaStr) return 9 * 60;
    const parts = horaStr.split(':');
    return parseInt(parts[0]) * 60 + parseInt(parts[1] || '0');
  }

  function minutosToHora(min) {
    const h = Math.floor(min / 60);
    const m = min % 60;
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
  }

  // Filtrar dias disponibles y priorizarlos
  // REGLA DE NEGOCIO: No se aceptan turnos para el mismo día. Mínimo = mañana.
  let diasBusqueda = dias.filter(d => d.abierto && d.disponible && d.fecha !== hoyStr);

  // Si se pidió una fecha específica, priorizarla
  if (fechaSolicitada) {
    const diaReq = diasBusqueda.find(d => d.fecha === fechaSolicitada);
    const diasOtros = diasBusqueda.filter(d => d.fecha !== fechaSolicitada);
    diasBusqueda = diaReq ? [diaReq, ...diasOtros] : diasOtros;
  }

  // Solo buscar en los próximos 14 días para consulta
  diasBusqueda = diasBusqueda.slice(0, 14);

  const candidatos = [];

  // ================================================================
  // JORNADA COMPLETA: servicios combinados que exceden el día laboral
  // ================================================================
  // Cuando la duración total supera las 10h (600 min), el loop normal
  // de slots no genera resultados. En la práctica, la estilista SÍ puede
  // hacer estos servicios en un día (paralleliza: trabaja uñas mientras
  // la química actúa en el cabello). Ofrecemos "jornada completa" en
  // días con baja carga.
  const JORNADA_MIN = CIERRE - APERTURA; // 600 min
  esJornadaCompleta = duracionServicio > JORNADA_MIN;

  if (esJornadaCompleta) {
    // Buscar días con carga < 20% (máx ~120 min de turnos existentes)
    const MAX_CARGA_JORNADA = 20;

    const diasJornada = diasBusqueda
      .filter(d => (d.carga_porcentaje || 0) < MAX_CARGA_JORNADA)
      .sort((a, b) => {
        // Priorizar día solicitado
        if (a.fecha === fechaSolicitada) return -1;
        if (b.fecha === fechaSolicitada) return 1;
        // Luego por menor carga
        return (a.carga_porcentaje || 0) - (b.carga_porcentaje || 0);
      })
      .slice(0, 3);

    for (const dia of diasJornada) {
      candidatos.push({
        fecha: dia.fecha,
        hora: minutosToHora(APERTURA),
        hora_fin: minutosToHora(CIERRE),
        nombre_dia: dia.nombre_dia,
        score: dia.fecha === fechaSolicitada ? 18 : 10,
        motivo: 'Jornada completa disponible',
        carga_dia: dia.carga_porcentaje || 0,
        jornada_completa: true
      });
    }

    console.log(`[AnalizarDisponibilidad] 🗓️ JORNADA COMPLETA: ${duracionServicio}min > ${JORNADA_MIN}min, ${diasJornada.length} días encontrados`);
  } else {
    // ================================================================
    // MODO NORMAL: generar slots por hora
    // ================================================================
    for (const dia of diasBusqueda) {
      if (candidatos.length >= 9) break; // suficientes candidatos

      // Obtener turnos del día con sus bloques de tiempo
      const turnosDelDia = (turnosPorDia[dia.fecha]?.turnos || []).map(t => {
        const horaStr = t.hora || '09:00';
        const startMin = horaToMinutos(horaStr);
        const dur = Number(t.duracion_min) || 60;
        return { start: startMin, end: startMin + dur };
      });

      // Generar slots disponibles
      for (let start = APERTURA; start + duracionServicio <= CIERRE; start += STEP) {
        const end = start + duracionServicio;

        // Hoy ya está excluido en diasBusqueda (regla de negocio: mínimo mañana)

        // Verificar que no solape con ningún turno existente
        const solapa = turnosDelDia.some(o => start < o.end && end > o.start);
        if (solapa) continue;

        // Puntuar el slot
        let score = 0;
        let motivo = 'Horario disponible';

        // +10 si coincide con hora_deseada exacta
        if (horaPreferida !== null && start === horaPreferida) {
          score += 10;
          motivo = 'Horario solicitado disponible';
        }

        // +8 si es el día solicitado
        if (dia.fecha === fechaSolicitada) {
          score += 8;
        }

        // +5 si encaja en preferencia de horario
        if (preferencia === 'manana' && start >= APERTURA && start < 12 * 60) {
          score += 5;
          if (motivo === 'Horario disponible') motivo = 'Disponible por la mañana';
        } else if (preferencia === 'tarde' && start >= 13 * 60 && start < CIERRE) {
          score += 5;
          if (motivo === 'Horario disponible') motivo = 'Disponible por la tarde';
        }

        // +3 si está adyacente a otro turno (pack calendar)
        if (turnosDelDia.length > 0) {
          const minGap = Math.min(...turnosDelDia.map(o =>
            Math.min(Math.abs(start - o.end), Math.abs(o.start - end))
          ));
          if (minGap <= 30) score += 3;
        }

        // +2 si el día tiene baja carga
        const loadPct = dia.carga_porcentaje || 0;
        if (loadPct < 30) score += 2;

        candidatos.push({
          fecha: dia.fecha,
          hora: minutosToHora(start),
          hora_fin: minutosToHora(end),
          nombre_dia: dia.nombre_dia,
          score,
          motivo,
          carga_dia: loadPct
        });
      }
    }
  }

  // Ordenar por score descendente y tomar top 3
  candidatos.sort((a, b) => b.score - a.score);

  const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

  slotsRecomendados = candidatos.slice(0, 3).map((s, i) => {
    const fechaObj = new Date(s.fecha + 'T12:00:00');
    const slot = {
      opcion: i + 1,
      fecha: s.fecha,
      hora: s.hora,
      hora_fin: s.hora_fin,
      nombre_dia: s.nombre_dia,
      fecha_humana: `${s.nombre_dia.toLowerCase()} ${fechaObj.getDate()} de ${meses[fechaObj.getMonth()]}`,
      motivo: s.motivo
    };
    if (s.jornada_completa) slot.jornada_completa = true;
    return slot;
  });
}

return [{
  json: {
    ...input,
    disponibilidad: dias,
    resumen_disponibilidad: resumen,
    capacidad_config: CAPACIDAD,
    turnos_existentes: turnos.length,
    // Nuevos campos para el agente
    // Mantener fecha original completa (con hora si viene) para BuildAgentPrompt
    fecha_solicitada: fechaSolicitadaRaw,
    fecha_disponible: fechaDisponible,
    motivo_no_disponible: motivoNoDisponible,
    alternativas: alternativas,
    // Servicio del turno existente (para comparar con servicio solicitado)
    turno_servicio_existente: turnoServicioExistente,
    // ID del turno en Odoo (para agregar servicio al turno existente)
    turno_id_existente: turnoIdExistente,
    // Precio del turno existente (para calcular seña diferencial)
    turno_precio_existente: turnoPrecioExistente,
    // Duración del turno existente en minutos (para sumar al agregar servicio)
    turno_duracion_existente: turnoDuracionExistente,
    // Complejidad del turno existente (para MAX al agregar servicio)
    turno_complejidad_existente: turnoComplejidadExistente,
    // Seña ya pagada del turno existente (para calcular diferencial)
    turno_sena_pagada: turnoSenaPagada,
    // Slots recomendados (solo en modo consultar_disponibilidad)
    slots_recomendados: slotsRecomendados,
    // Jornada completa: servicios combinados exceden el día laboral
    jornada_completa: esJornadaCompleta,
    // Acción explícita (no depender solo de ...input spread)
    accion: input.accion || null
  }
}];

